<?php declare(strict_types=1); require_once dirname(__DIR__) . '/config/bootstrap.php'; ns_redirect_legacy_url('/ferramentas/calculadora-multa-atraso'); ns_render_page_start('tool:calculadora-multa-atraso'); ?>
<main><div class="tool-page"><nav class="breadcrumb" aria-label="Navegação breadcrumb"><a href="<?= ns_escape(ns_href('/')) ?>">Início</a><span class="sep">›</span><a href="<?= ns_escape(ns_href('/ferramentas')) ?>">Ferramentas</a><span class="sep">›</span><span>Calculadora de Multa por Atraso</span></nav><?php ns_render_ad_slot('leaderboard'); ?><div class="tool-header"><div class="tool-page-icon" style="background:linear-gradient(135deg,#fff1eb,#ffd4c2);">⏰</div><div><h1>Calculadora de Multa por Atraso</h1><p>Calcule multa, juros e total atualizado para cobranças com atraso de forma rápida e objetiva.</p><span class="tag tag-orange">Finanças</span></div></div><div class="tool-box"><div class="form-row"><div class="form-group"><label for="ma-valor">Valor original (R$)</label><input id="ma-valor" class="form-control" type="number" min="0" step="0.01"></div><div class="form-group"><label for="ma-multa">Multa (%)</label><input id="ma-multa" class="form-control" type="number" min="0" step="0.01" value="2"></div><div class="form-group"><label for="ma-juros">Juros ao mês (%)</label><input id="ma-juros" class="form-control" type="number" min="0" step="0.01" value="1"></div><div class="form-group"><label for="ma-dias">Dias de atraso</label><input id="ma-dias" class="form-control" type="number" min="0" step="1"></div></div><div class="form-row"><button class="btn btn-primary" type="button" onclick="calcMA()">Calcular</button><button class="btn btn-outline" type="button" onclick="clearMA()">Limpar</button><button class="copy-btn" type="button" onclick="copyMA(this)">Copiar resultado</button></div><div class="notice notice-warn" id="ma-erro" style="display:none;"><span>⚠️</span><span id="ma-erro-texto"></span></div><div class="result-box" id="ma-res"><div class="result-grid"><div class="result-item"><div class="label">Multa</div><div class="value" id="ma-multa-res">—</div></div><div class="result-item"><div class="label">Juros</div><div class="value" id="ma-juros-res">—</div></div><div class="result-item"><div class="label">Total</div><div class="value" id="ma-total-res">—</div></div></div><div id="ma-det" style="margin-top:1rem;color:var(--text2);"></div></div></div><?php ns_render_ad_slot('rectangle'); ?><div class="seo-content"><h2>O que é essa ferramenta</h2><p>Esta calculadora ajuda a estimar o valor atualizado de uma cobrança atrasada com multa e juros. É útil para negociações, acordos, controle financeiro e conferência rápida de boletos ou cobranças internas.</p><h2>Como usar</h2><p>Informe o valor original, o percentual de multa, a taxa de juros mensal e os dias de atraso. Depois clique em calcular para ver multa, juros estimados e total atualizado.</p><h2>Exemplo de uso</h2><p>Se uma cobrança de R$ 500 tem multa de 2%, juros de 1% ao mês e atraso de 15 dias, a ferramenta calcula uma estimativa simples para facilitar a conferência.</p><h2>Perguntas frequentes</h2><h3>O cálculo é jurídico?</h3><p>Não. É uma estimativa simples para conferência operacional.</p><h3>Os juros são proporcionais?</h3><p>Sim. Nesta versão, os juros mensais são proporcionais aos dias informados.</p><h3>Posso usar em negociação?</h3><p>Sim, como referência rápida antes de validar regras específicas do contrato.</p></div></div></main><script>function maErr(m){document.getElementById('ma-erro-texto').textContent=m;document.getElementById('ma-erro').style.display='flex';document.getElementById('ma-res').classList.remove('show')} function maClearErr(){document.getElementById('ma-erro').style.display='none'} function calcMA(){const v=parseFloat(maValor.value),m=parseFloat(maMulta.value),j=parseFloat(maJuros.value),d=parseInt(maDias.value||'0',10);maClearErr();if(isNaN(v)||isNaN(m)||isNaN(j)||isNaN(d)||v<=0||d<0){maErr('Preencha os campos com valores válidos.');return}const multa=v*(m/100),juros=v*(j/100)*(d/30),total=v+multa+juros;maMultaRes.textContent='R$ '+fmtBRL(multa);maJurosRes.textContent='R$ '+fmtBRL(juros);maTotalRes.textContent='R$ '+fmtBRL(total);maDet.textContent='Estimativa com multa fixa e juros simples proporcionais aos dias de atraso.';showResult('ma-res')} function clearMA(){['maValor','maMulta','maJuros','maDias'].forEach(id=>document.getElementById(id.replace(/[A-Z]/g,m=>'-'+m.toLowerCase())));document.getElementById('ma-valor').value='';document.getElementById('ma-multa').value='2';document.getElementById('ma-juros').value='1';document.getElementById('ma-dias').value='';document.getElementById('ma-res').classList.remove('show');maClearErr()} function copyMA(b){if(!document.getElementById('ma-res').classList.contains('show')){maErr('Calcule antes de copiar.');return}copyToClipboard('Multa: '+maMultaRes.textContent+'\nJuros: '+maJurosRes.textContent+'\nTotal: '+maTotalRes.textContent,b)} const maValor=document.getElementById('ma-valor'),maMulta=document.getElementById('ma-multa'),maJuros=document.getElementById('ma-juros'),maDias=document.getElementById('ma-dias'),maMultaRes=document.getElementById('ma-multa-res'),maJurosRes=document.getElementById('ma-juros-res'),maTotalRes=document.getElementById('ma-total-res'),maDet=document.getElementById('ma-det');</script><?php ns_render_page_end(); ?>
